import { describe, expect, it } from 'vitest';

import {
  bigBangReach,
  pillarFutureAnchor,
  pillarPastAnchor,
  pillarPresentAnchor,
  threePillarReport,
} from '../src/pillar-anchors';
import {
  TOWER_CEILINGS,
  vacuumBuleyProjection,
  type BuleyProjection,
} from '../src/spectral-noise-monitor';

describe('Pillar I — Past — big-bang reach', () => {
  it('vacuum reaches itself with zero clinamen lifts', () => {
    const reached = bigBangReach(vacuumBuleyProjection);
    expect(reached).toEqual(vacuumBuleyProjection);
  });

  it('reaches a pure-waste Bule unit by waste-only lifts', () => {
    const target: BuleyProjection = { waste: 5, opportunity: 0, diversity: 0, score: 5 };
    expect(bigBangReach(target)).toEqual(target);
  });

  it('reaches a mixed Bule unit by waste-then-opportunity-then-diversity lifts', () => {
    const target: BuleyProjection = { waste: 2, opportunity: 3, diversity: 1, score: 6 };
    expect(bigBangReach(target)).toEqual(target);
  });

  it('past-anchor passes for every reachable Bule unit', () => {
    const samples: BuleyProjection[] = [
      vacuumBuleyProjection,
      { waste: 1, opportunity: 0, diversity: 0, score: 1 },
      { waste: 2, opportunity: 3, diversity: 1, score: 6 },
      { waste: 18, opportunity: 0, diversity: 0, score: 18 },
    ];
    for (const b of samples) {
      expect(pillarPastAnchor(b)).toBe(true);
    }
  });
});

describe('Pillar II — Present — topological-metabolism ceiling', () => {
  it('vacuum is inside every manifold', () => {
    const result = pillarPresentAnchor(vacuumBuleyProjection);
    expect(result.insideManifold).toBe(true);
    expect(result.violation).toBeNull();
  });

  it('Hexon-pressure (score 6) sits exactly at the Hexon ceiling — inside', () => {
    const b: BuleyProjection = { waste: 6, opportunity: 0, diversity: 0, score: 6 };
    const result = pillarPresentAnchor(b);
    expect(result.ceiling).toBe(TOWER_CEILINGS.hexon);
    expect(result.insideManifold).toBe(true);
  });

  it('Trihexon-pressure (score 18) violates the Hexon manifold by 12', () => {
    const b: BuleyProjection = { waste: 18, opportunity: 0, diversity: 0, score: 18 };
    const result = pillarPresentAnchor(b);
    expect(result.insideManifold).toBe(false);
    expect(result.violation).toEqual({
      ceiling: TOWER_CEILINGS.hexon,
      score: 18,
      correctiveContractCount: 12,
    });
  });

  it('a brown-noise spectral pressure (score 7) violates Hexon by 1', () => {
    const b: BuleyProjection = { waste: 4, opportunity: 1, diversity: 2, score: 7 };
    const result = pillarPresentAnchor(b);
    expect(result.insideManifold).toBe(false);
    expect(result.violation).toEqual({
      ceiling: TOWER_CEILINGS.hexon,
      score: 7,
      correctiveContractCount: 1,
    });
  });
});

describe('Pillar III — Future — no-free-lunch / no-cloning', () => {
  it('vacuum admits free duplication (score 0)', () => {
    const result = pillarFutureAnchor(vacuumBuleyProjection);
    expect(result.freeDuplication).toBe(true);
    expect(result.cloningEntropy).toBe(0);
    expect(result.clonedPairScore).toBe(0);
  });

  it('a positive-score Bule unit forbids free duplication', () => {
    const b: BuleyProjection = { waste: 6, opportunity: 0, diversity: 0, score: 6 };
    const result = pillarFutureAnchor(b);
    expect(result.freeDuplication).toBe(false);
    expect(result.cloningEntropy).toBe(6);
    expect(result.clonedPairScore).toBe(12);
  });

  it('cloning entropy equals source score for every state', () => {
    const samples: BuleyProjection[] = [
      vacuumBuleyProjection,
      { waste: 1, opportunity: 0, diversity: 0, score: 1 },
      { waste: 2, opportunity: 3, diversity: 1, score: 6 },
      { waste: 18, opportunity: 0, diversity: 0, score: 18 },
    ];
    for (const b of samples) {
      const result = pillarFutureAnchor(b);
      expect(result.cloningEntropy).toBe(b.score);
    }
  });
});

describe('three-pillar bundle report', () => {
  it('vacuum passes all three pillars trivially', () => {
    const report = threePillarReport(vacuumBuleyProjection);
    expect(report.past.anchored).toBe(true);
    expect(report.present.insideManifold).toBe(true);
    expect(report.future.freeDuplication).toBe(true);
  });

  it('Hexon-edge state passes past + present, fails future free-duplication', () => {
    const b: BuleyProjection = { waste: 6, opportunity: 0, diversity: 0, score: 6 };
    const report = threePillarReport(b);
    expect(report.past.anchored).toBe(true);
    expect(report.present.insideManifold).toBe(true);
    expect(report.future.freeDuplication).toBe(false);
    expect(report.future.cloningEntropy).toBe(6);
  });

  it('Trihexon state passes past, fails present (Hexon violation), fails future', () => {
    const b: BuleyProjection = { waste: 18, opportunity: 0, diversity: 0, score: 18 };
    const report = threePillarReport(b);
    expect(report.past.anchored).toBe(true);
    expect(report.present.insideManifold).toBe(false);
    expect(report.present.violation?.correctiveContractCount).toBe(12);
    expect(report.future.freeDuplication).toBe(false);
    expect(report.future.cloningEntropy).toBe(18);
  });

  it('respects custom ceiling on the present pillar', () => {
    const b: BuleyProjection = { waste: 6, opportunity: 0, diversity: 0, score: 6 };
    const report = threePillarReport(b, TOWER_CEILINGS.triton);
    // Hexon-edge violates Triton ceiling (3) by 3
    expect(report.present.insideManifold).toBe(false);
    expect(report.present.violation?.correctiveContractCount).toBe(3);
  });
});
